import { users, addUsersToAdminRole } from "@/services/api"
import { Button, Col, message, Modal, Row, Typography, Space } from "antd"
import { useEffect, useRef, useState } from "react"
import { API } from '@/services/typings';
import ProTable, { ActionType } from "@ant-design/pro-table";
import { getTablePaginationConfig, t } from "@/global";
import { CloseOutlined } from "@ant-design/icons";
import { useModel } from "@umijs/max";
import { getLocalSortState, handleSortStateChange } from "@/components/Others/table_sort";
import { USER_LIST_SORT_STATE_KEY, userColumns } from "../../UserList";

type Props = {
  visible: boolean
  setVisible: React.Dispatch<React.SetStateAction<boolean>>
  roleGuid: string,
  closeChangedCallback: () => void;
}

const app: React.FC<Props> = (props) => {
  const [selectedRowKeys, setSelectedRowKeys] = useState<string[]>([]);
  const [everChanged, setEverChanged] = useState<boolean>(false);
  const [sortState, setSortState] = useState<API.SortState>(() => getLocalSortState(USER_LIST_SORT_STATE_KEY));
  const actionRef = useRef<ActionType>();
  const { initialState } = useModel('@@initialState');

  useEffect(() => {
    if (props.visible) {
      actionRef.current?.reload();
    }
  }, [props.visible]);

  const onSave = async () => {
    const hide = message.loading('Updating');
    try {
      const guids = selectedRowKeys as string[];
      await addUsersToAdminRole(props.roleGuid, {
        data: { users: guids }
      });
      hide();
      message.success(`${guids.length} record${guids.length === 1 ? " is" : "s are"} successfully changed`);
    } catch (e: any) {
      hide();
      message.error(typeof e === 'string' ? e : 'Failed to update users');
    }
    setEverChanged(true);
    actionRef.current?.clearSelected?.();
    actionRef.current?.reload();
  }

  const onReset = async () => {
    actionRef.current?.reset?.();
  }

  const saveButtonEnabled = () => {
    return selectedRowKeys.length > 0;
  }

  const onClose = () => {
    props.setVisible(false);
    setSelectedRowKeys([]);
    if (everChanged) props.closeChangedCallback();
    setEverChanged(false);
  }

  const columns = userColumns({
    actionRef,
    myname: initialState?.user?.name,
    is_select: true,
    sortState,
    setSortState,
  });

  return <Modal
    open={props.visible}
    width="90vw"
    style={{
      overflowX: "hidden",
    }}
    footer={saveButtonEnabled() ?
      <Row justify="center" gutter={16}>
        <Col>
          <Button onClick={onReset}>{t("Reset")}</Button>
        </Col>
        <Col>
          <Button onClick={onSave} type="primary">{t("Save")}</Button>
        </Col>
      </Row>
      : null}
    onCancel={onClose}
    destroyOnClose={true}
    title={
      <Space direction="vertical" size={4}>
        <Typography.Title level={4} style={{ margin: 0 }}>
          {t('Add users to role', true)}
        </Typography.Title>
        <Typography.Text type="secondary">
          {t('admin_not_restricted_by_roles', true)}
        </Typography.Text>
      </Space>
    }
    closeIcon={<CloseOutlined />}
  >
    <ProTable<API.UserListItem, API.PageParams & { without_admin_role_guid: string } >
      columnsState={{ persistenceType: 'localStorage', persistenceKey: 'role_assign_users_columns_state' }}
      rowKey={"guid"}
      actionRef={actionRef}
      search={{ filterType: 'light' }}
      defaultSize="middle"
      columns={columns as any}
      params={{
        without_admin_role_guid: props.roleGuid,
      }}
      request={users}
      rowSelection={{
        selectedRowKeys: selectedRowKeys,
        onChange: (selectedRowKeys) => {
          setSelectedRowKeys(selectedRowKeys as string[]);
        },
      }}
      pagination={getTablePaginationConfig('role_assign_user_list')}
      style={{
        paddingLeft: '5vw', paddingRight: '5vw'
      }}
      onChange={(_, __, sorter) => handleSortStateChange(sorter, actionRef, USER_LIST_SORT_STATE_KEY, setSortState)}
    />
  </Modal >
}

export default app;

