import { Button, message } from 'antd';
import { SelectOutlined } from '@ant-design/icons';
import React, { useState, useRef, useEffect } from 'react';
import { FooterToolbar } from '@ant-design/pro-layout';
import type { ActionType } from '@ant-design/pro-table';
import ProTable from '@ant-design/pro-table';
import { users, getAdminRole, removeUsersFromAdminRole } from '@/services/api';
import { API } from '@/services/typings';
import { useModel } from '@umijs/max';
import { t, getTablePaginationConfig, renderDetails } from '../../../global';
import UserSelect from './UserSelect';
import { getLocalSortState, handleSortStateChange } from '@/components/Others/table_sort';
import { USER_LIST_SORT_STATE_KEY, userColumns } from '@/pages/UserList';

type RoleUserListProps = {
  roleGuid: string;
  setRole: React.Dispatch<React.SetStateAction<API.AdminRoleListItem | undefined>>;
}

const UserTable: React.FC<RoleUserListProps> = (props) => {
  const actionRef = useRef<ActionType>();
  const [selectedRowsState, setSelectedRows] = useState<API.UserListItem[]>([]);
  const [userSelectVisible, setUserSelectVisible] = useState<boolean>(false);
  const { initialState } = useModel('@@initialState');
  const is_admin = initialState?.user?.is_admin;
  const [sortState, setSortState] = useState<API.SortState>(() => getLocalSortState(USER_LIST_SORT_STATE_KEY));
  const [showDetail, setShowDetail] = useState<boolean>(false);
  const [currentRow, setCurrentRow] = useState<API.UserListItem>();

  useEffect(() => {
    fetchRoleInfo();
    actionRef.current?.reload();
  }, []);

  const fetchRoleInfo = async () => {
    try {
      const currentRole = await getAdminRole(props.roleGuid);
      if (currentRole) {
        props.setRole(currentRole);
      }
    } catch (error) {
      message.error(t('Failed to fetch role info'));
    }
  };

  const handleRemove = async (guids: string[]) => {
    const hide = message.loading(t('Updating'));
    try {
      await removeUsersFromAdminRole(props.roleGuid, {
        data: { users: guids }
      });
      hide();
      message.success(`${guids.length} 'user'${guids.length === 1 ? "" : "s"} 'removed successfully'`);
    } catch (e: any) {
      hide();
      message.error(e);
    }
    actionRef.current?.clearSelected?.();
    actionRef.current?.reload();
  };

  const columns = userColumns({
    actionRef,
    myname: initialState?.user?.name,
    is_select: false,
    sortState,
    setSortState,
    onIdClick: (entity: API.UserListItem) => {
      setCurrentRow(entity);
      setShowDetail(true);
    },
  });

  return (
    <div>
      <ProTable<API.UserListItem, API.PageParams & { admin_role_guid: string }>
        headerTitle={t('User List')}
        actionRef={actionRef}
        columnsState={{ persistenceType: 'localStorage', persistenceKey: 'role_userlist_columns_state' }}
        rowKey="guid"
        search={{
          labelWidth: 120,
        }}
        params={{
          admin_role_guid: props.roleGuid,
        }}
        request={users}
        columns={columns}
        toolBarRender={() => [
          <Button
            type="primary"
            key="primary"
            onClick={() => {
              setUserSelectVisible(true);
            }}
          >
            <SelectOutlined /> {t('add_users')}
          </Button>,
        ]}
        rowSelection={
          is_admin
            ? {
              onChange: (_, selectedRows) => {
                setSelectedRows(selectedRows);
              },
            }
            : undefined
        }
        onChange={(_, __, sorter) => {
          handleSortStateChange(sorter, actionRef, USER_LIST_SORT_STATE_KEY, setSortState);
        }}
        pagination={getTablePaginationConfig("role_user_list")}
      />
      {selectedRowsState?.length > 0 && (
        <FooterToolbar
          extra={
            <div>
              {t('Chosen')} <a style={{ fontWeight: 600 }}>{selectedRowsState.length}</a>{' '}
              {t('Items')}
            </div>
          }
        >
          <Button onClick={() => {
            handleRemove(selectedRowsState.map(row => row.guid));
          }}>{t('Remove', true)}</Button>
        </FooterToolbar>
      )}
      <UserSelect
        visible={userSelectVisible}
        setVisible={setUserSelectVisible}
        roleGuid={props.roleGuid}
        closeChangedCallback={() => {
          actionRef.current?.reload();
          fetchRoleInfo();
        }}
      ></UserSelect>
      {renderDetails(
        showDetail,
        currentRow?.guid,
        currentRow,
        columns.slice(0, columns.length - 1),
        setCurrentRow,
        setShowDetail,
      )}
    </div>
  );
};

export default UserTable;

